def topo_columns(nodes, out_edges):
    indegree = {n: 0 for n in nodes}
    for n in nodes:
        for lk in out_edges[n]:
            indegree[lk["target"]] += 1
    col = {n: 0 for n in nodes}   # initialise all nodes at column 0
    queue = deque([n for n in nodes if indegree[n] == 0])
    while queue:
        n = queue.popleft()
        c = col[n]
        for lk in out_edges[n]:
            t = lk["target"]
            col[t] = max(col[t], c + 1)
            indegree[t] -= 1
            if indegree[t] == 0:
                queue.append(t)
    return col
